<template><div class="page"><div class="head"><div><h2>直播课堂</h2><p>加入已选课程直播，结束后可观看回放</p></div><el-button @click="load">刷新</el-button></div>
<el-tabs v-model="tab"><el-tab-pane label="直播安排" name="live"/>
<el-tab-pane label="回放视频" name="replay"/></el-tabs>
<el-empty v-if="!loading&&!displayList.length" :description="tab==='live'?'暂无直播安排':'暂无回放视频'"/>
<div class="grid" v-loading="loading"><el-card v-for="r in displayList" :key="r.room_id"><div class="status" :class="tab==='replay'?'ready':r.status">{{ tab==='replay'?'回放':labels[r.status] }}</div><h3>{{r.title}}</h3><p>{{r.course_name}} · {{r.teacher_name}}</p><p>{{tab==='replay'?fmt(r.record_start_time):fmt(r.scheduled_start)}}</p><p v-if="tab==='replay'&&r.replay_duration" class="duration">时长：{{fmtDuration(r.replay_duration)}}</p><el-button v-if="r.status==='live'" type="danger" @click="$router.push('/student/live/'+r.room_id)">进入直播</el-button><el-button v-else-if="tab==='replay'||r.replay_status==='ready'" type="primary" @click="$router.push('/student/live/'+r.room_id)">观看回放</el-button></el-card></div></div></template>
<script setup>import{ref,computed,onMounted}from'vue';import{studentRooms,studentReplays}from'../../api/live';const tab=ref('live'),rooms=ref([]),replays=ref([]),loading=ref(false),labels={scheduled:'未开始',live:'直播中',ended:'已结束',cancelled:'已取消'};const displayList=computed(()=>tab.value==='live'?rooms.value:replays.value);const fmt=v=>v?new Date(v).toLocaleString():'--';const fmtDuration=s=>{if(!s||s<=0)return'--';const m=Math.floor(s/60),r=s%60;return m>0?`${m}分${r}秒`:`${r}秒`};async function load(){loading.value=true;try{const[r,re]=await Promise.all([studentRooms(),studentReplays()]);rooms.value=r;replays.value=re||[]}finally{loading.value=false}}onMounted(load)</script>
<style scoped>.page{background:#fff;padding:24px;border-radius:16px}.head{display:flex;justify-content:space-between}.head p,p{color:#64748b}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(280px,1fr));gap:16px;margin-top:20px}.status{float:right;padding:4px 10px;border-radius:12px;background:#eef2ff}.status.live{background:#fee2e2;color:#dc2626}.status.ready{background:#dcfce7;color:#16a34a}.duration{color:#64748b;font-size:13px}</style>